import { router } from "@inertiajs/react";
import {
    type ColumnDef,
    type ColumnFiltersState,
    type ColumnOrderState,
    type RowSelectionState,
    type SortingState,
    type VisibilityState,
    getCoreRowModel,
    useReactTable,
} from "@tanstack/react-table";
import { useCallback, useEffect, useState } from "react";
import type { DataTableColumnDef, DataTableResponse } from "./types";

const STORAGE_PREFIX = "dt-columns-";
const ORDER_STORAGE_PREFIX = "dt-column-order-";

function loadVisibility(tableName: string, columns: DataTableColumnDef[]): VisibilityState {
    const stored = localStorage.getItem(STORAGE_PREFIX + tableName);
    if (stored) {
        try {
            return JSON.parse(stored) as VisibilityState;
        } catch {
            // fall through
        }
    }
    const visibility: VisibilityState = {};
    for (const col of columns) {
        visibility[col.id] = col.visible;
    }
    return visibility;
}

function saveVisibility(tableName: string, visibility: VisibilityState) {
    localStorage.setItem(STORAGE_PREFIX + tableName, JSON.stringify(visibility));
}

function loadColumnOrder(tableName: string, columns: DataTableColumnDef[]): ColumnOrderState {
    const stored = localStorage.getItem(ORDER_STORAGE_PREFIX + tableName);
    if (stored) {
        try {
            return JSON.parse(stored) as ColumnOrderState;
        } catch {
            // fall through
        }
    }
    return columns.map((col) => col.id);
}

function saveColumnOrder(tableName: string, order: ColumnOrderState) {
    localStorage.setItem(ORDER_STORAGE_PREFIX + tableName, JSON.stringify(order));
}

interface UseDataTableOptions<TData> {
    tableData: DataTableResponse<TData>;
    tableName: string;
    columnDefs: ColumnDef<TData>[];
}

export function useDataTable<TData>({ tableData, tableName, columnDefs }: UseDataTableOptions<TData>) {
    const { meta } = tableData;

    const [columnVisibility, setColumnVisibility] = useState<VisibilityState>(() =>
        loadVisibility(tableName, tableData.columns),
    );

    const [columnOrder, setColumnOrder] = useState<ColumnOrderState>(() =>
        loadColumnOrder(tableName, tableData.columns),
    );

    const [sorting, setSorting] = useState<SortingState>(() =>
        meta.sorts.map((s) => ({ id: s.id, desc: s.direction === "desc" })),
    );

    const [columnFilters, setColumnFilters] = useState<ColumnFiltersState>([]);
    const [rowSelection, setRowSelection] = useState<RowSelectionState>({});

    const navigate = useCallback(
        (params: Record<string, unknown>) => {
            const currentUrl = new URL(window.location.href);
            const searchParams = new URLSearchParams(currentUrl.search);

            for (const [key, value] of Object.entries(params)) {
                if (value === null || value === undefined || value === "") {
                    searchParams.delete(key);
                } else {
                    searchParams.set(key, String(value));
                }
            }

            router.get(
                currentUrl.pathname + "?" + searchParams.toString(),
                {},
                { preserveScroll: true },
            );
        },
        [],
    );

    const handleSort = useCallback(
        (columnId: string, multi: boolean) => {
            const currentSorts = meta.sorts;

            if (multi) {
                const newSorts = [...currentSorts];
                const idx = newSorts.findIndex((s) => s.id === columnId);
                if (idx === -1) {
                    newSorts.push({ id: columnId, direction: "asc" });
                } else if (newSorts[idx].direction === "asc") {
                    newSorts[idx] = { ...newSorts[idx], direction: "desc" };
                } else {
                    newSorts.splice(idx, 1);
                }
                const param = newSorts
                    .map((s) => (s.direction === "desc" ? `-${s.id}` : s.id))
                    .join(",");
                navigate({ sort: param || null, page: null });
            } else {
                const existing = currentSorts.find((s) => s.id === columnId);
                let newSort: string | null;
                if (existing?.direction === "asc") {
                    newSort = "-" + columnId;
                } else if (existing?.direction === "desc") {
                    newSort = null;
                } else {
                    newSort = columnId;
                }
                navigate({ sort: newSort, page: null });
            }
        },
        [meta.sorts, navigate],
    );

    const handlePageChange = useCallback(
        (page: number) => {
            navigate({ page: page > 1 ? page : null });
        },
        [navigate],
    );

    const handlePerPageChange = useCallback(
        (perPage: number) => {
            navigate({ per_page: perPage, page: null });
        },
        [navigate],
    );

    const handleApplyQuickView = useCallback(
        (params: Record<string, unknown>) => {
            const currentUrl = new URL(window.location.href);
            const searchParams = new URLSearchParams();

            for (const [key, value] of Object.entries(params)) {
                if (value !== null && value !== undefined && value !== "") {
                    searchParams.set(key, String(value));
                }
            }

            const perPage = currentUrl.searchParams.get("per_page");
            if (perPage) {
                searchParams.set("per_page", perPage);
            }

            router.get(
                currentUrl.pathname + "?" + searchParams.toString(),
                {},
                { preserveScroll: true },
            );
        },
        [],
    );

    const applyColumns = useCallback(
        (columnIds: string[]) => {
            const newVisibility: VisibilityState = {};
            for (const col of tableData.columns) {
                newVisibility[col.id] = columnIds.includes(col.id);
            }
            setColumnVisibility(newVisibility);
            setColumnOrder(columnIds);
        },
        [tableData.columns],
    );

    // eslint-disable-next-line react-hooks/incompatible-library
    const table = useReactTable<TData>({
        data: tableData.data,
        columns: columnDefs,
        manualPagination: true,
        manualSorting: true,
        manualFiltering: true,
        pageCount: meta.lastPage,
        onSortingChange: setSorting,
        onColumnFiltersChange: setColumnFilters,
        onColumnVisibilityChange: setColumnVisibility,
        onColumnOrderChange: setColumnOrder,
        onRowSelectionChange: setRowSelection,
        enableRowSelection: true,
        getCoreRowModel: getCoreRowModel(),
        initialState: {
            columnPinning: {
                left: columnDefs.some((c) => c.id === "_select") ? ["_select"] : [],
                right: columnDefs.some((c) => c.id === "_actions") ? ["_actions"] : [],
            },
        },
        state: {
            sorting,
            columnFilters,
            columnVisibility,
            columnOrder,
            rowSelection,
            pagination: {
                pageIndex: meta.currentPage - 1,
                pageSize: meta.perPage,
            },
        },
    });

    useEffect(() => {
        saveVisibility(tableName, columnVisibility);
    }, [tableName, columnVisibility]);

    useEffect(() => {
        saveColumnOrder(tableName, columnOrder);
    }, [tableName, columnOrder]);

    const handleApplyCustomSearch = useCallback(
        (search: string) => {
            const currentUrl = new URL(window.location.href);
            router.get(
                currentUrl.pathname + search,
                {},
                { preserveScroll: true },
            );
        },
        [],
    );

    return {
        table,
        meta,
        columnVisibility,
        columnOrder,
        setColumnOrder,
        rowSelection,
        setRowSelection,
        applyColumns,
        handleSort,
        handlePageChange,
        handlePerPageChange,
        handleApplyQuickView,
        handleApplyCustomSearch,
    };
}

import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from "@/components/ui/command";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";
import { ArrowRightIcon, ChevronRightIcon, FilterIcon, Trash2, X } from "lucide-react";
import React, { useEffect, useMemo, useRef, useState } from "react";
import { FilterControl } from "./filter-controls";
import type { FilterColumn, FilterValue } from "./types";
import { DEFAULT_OPERATOR, OPERATORS } from "./types";
import { useFilters } from "./use-filters";

interface FiltersProps {
    columns: FilterColumn[];
    serverFilters: Record<string, unknown>;
}

function formatNumericValue(v: string): string {
    const n = Number(v);
    if (Number.isFinite(n)) {
        return n.toLocaleString("fr-TN");
    }
    return v;
}

const BOOL_LABELS: Record<string, string> = { "1": "Oui", "0": "Non" };

function formatValueLabel(
    column: FilterColumn,
    values: string[]
): string {
    if (column.type === "boolean") {
        return values.map((v) => BOOL_LABELS[v] ?? v).join(", ");
    }
    if (column.type === "option" && column.options) {
        const labels = values
        .map((v) => column.options!.find((o) => o.value === v)?.label ?? v)
        .slice(0, 3);
        const suffix = values.length > 3 ? ` +${values.length - 3}` : "";
        return labels.join(", ") + suffix;
    }
    if (column.type === "number") {
        if (values.length === 2) {
            return `${formatNumericValue(values[0])} – ${formatNumericValue(values[1])}`;
        }
        return values.map(formatNumericValue).join(", ");
    }
    if (values.length === 2) {
        return `${values[0]} – ${values[1]}`;
    }
    return values.join(", ");
}

function getOperatorLabel(column: FilterColumn, operator: string): string {
    const opDef = OPERATORS[column.type]?.find((o) => o.value === operator);
    return opDef?.label ?? operator;
}

type PillSection = "operator" | "value";

function FilterPill({
                        column,
                        filterValue,
                        openSection,
                        onSectionChange,
                        onClear,
                        onSubmit
                    }: {
    column: FilterColumn;
    filterValue: FilterValue;
    openSection: PillSection | null;
    onSectionChange: (section: PillSection | null) => void;
    onClear: () => void;
    onSubmit: (op: string, vals: string[]) => void;
}) {
    const Icon = column.icon;
    const ops = OPERATORS[column.type];

    function handleOperatorSelect(op: string) {
        onSectionChange(null);
        onSubmit(op, filterValue.values);
    }

    return (
        <div
            className="group/pill flex h-7 items-center rounded-2xl border border-border bg-background text-xs shadow-xs transition-colors duration-150 has-[>[data-slot=clear]:hover]:border-destructive/40 has-[>[data-slot=clear]:hover]:bg-destructive/5">
            <span className="flex select-none items-center gap-1 whitespace-nowrap px-2 font-medium">
                {Icon && <Icon className="size-3.5 stroke-[2.25px]" />}
                <span>{column.label}</span>
            </span>
            <Separator orientation="vertical" />

            {/* Operator section — clickable popover */}
            <Popover
                open={openSection === "operator"}
                onOpenChange={(open) => onSectionChange(open ? "operator" : null)}
            >
                <PopoverTrigger asChild>
                    <button
                        type="button"
                        className="h-full whitespace-nowrap px-2 text-muted-foreground hover:bg-accent transition-colors"
                    >
                        {getOperatorLabel(column, filterValue.operator)}
                    </button>
                </PopoverTrigger>
                <PopoverContent
                    className="w-fit p-0 origin-(--radix-popover-content-transform-origin)"
                    align="start"
                >
                    <Command loop>
                        <CommandList className="max-h-fit">
                            <CommandGroup heading="Opérateurs">
                                {ops.map((op) => (
                                    <CommandItem
                                        key={op.value}
                                        value={op.value}
                                        onSelect={() => handleOperatorSelect(op.value)}
                                    >
                                        {op.label}
                                    </CommandItem>
                                ))}
                            </CommandGroup>
                        </CommandList>
                    </Command>
                </PopoverContent>
            </Popover>

            <Separator orientation="vertical" />

            {/* Value section — clickable popover */}
            <Popover
                open={openSection === "value"}
                onOpenChange={(open) => onSectionChange(open ? "value" : null)}
            >
                <PopoverTrigger asChild>
                    <button
                        type="button"
                        className={cn(
                            "h-full whitespace-nowrap px-2 max-w-[200px] truncate hover:bg-accent transition-colors",
                            column.type === "number" && "tabular-nums"
                        )}
                    >
                        {formatValueLabel(column, filterValue.values)}
                    </button>
                </PopoverTrigger>
                <PopoverContent className="p-0 w-auto" align="start">
                    <FilterControl
                        column={column}
                        value={filterValue}
                        onSubmit={onSubmit}
                        hideOperator
                    />
                </PopoverContent>
            </Popover>

            <Separator orientation="vertical" />
            <button
                type="button"
                data-slot="clear"
                onClick={onClear}
                className="flex h-full items-center rounded-r-2xl px-1.5 transition-colors duration-150 hover:bg-destructive hover:text-white"
            >
                <X className="size-3.5" />
            </button>
        </div>
    );
}

export function Filters({ columns, serverFilters }: FiltersProps) {
    const { activeFilters, setFilter, clearFilter, clearAllFilters } = useFilters(serverFilters);

    const [selectorOpen, setSelectorOpen] = useState(false);
    const [selectorColumn, setSelectorColumn] = useState<string | null>(null);
    const [openPill, setOpenPill] = useState<{ columnId: string; section: PillSection } | null>(null);
    const [search, setSearch] = useState("");
    const inputRef = useRef<HTMLInputElement>(null);

    const hasActiveFilters = Object.keys(activeFilters).length > 0;

    const optionColumns = useMemo(
        () => columns.filter((c) => c.type === "option" && c.options),
        [columns]
    );

    useEffect(() => {
        if (selectorColumn) {
            inputRef.current?.focus();
        }
    }, [selectorColumn]);

    useEffect(() => {
        if (!selectorOpen) {
            setTimeout(() => {
                setSelectorColumn(null);
                setSearch("");
            }, 150);
        }
    }, [selectorOpen]);

    function closeAll() {
        setSelectorOpen(false);
        setSelectorColumn(null);
        setOpenPill(null);
    }

    function handleSelectorOpenChange(open: boolean) {
        setSelectorOpen(open);
        if (open) setOpenPill(null);
    }

    function handlePillSectionChange(columnId: string, section: PillSection | null) {
        if (section) {
            setSelectorOpen(false);
            setSelectorColumn(null);
            setOpenPill({ columnId, section });
        } else {
            setOpenPill(null);
        }
    }

    function handleFilterSubmit(columnId: string, operator: string, values: string[]) {
        setFilter(columnId, operator, values);
    }

    function handleQuickOptionToggle(columnId: string, optionValue: string) {
        const current = activeFilters[columnId];
        const operator = current?.operator || DEFAULT_OPERATOR.option;
        const values = new Set(current?.values ?? []);
        if (values.has(optionValue)) values.delete(optionValue);
        else values.add(optionValue);
        setFilter(columnId, operator, Array.from(values));
    }

    const selectedColumn = selectorColumn
        ? columns.find((c) => c.id === selectorColumn)
        : null;

    return (
        <div className="flex flex-wrap items-center gap-1.5">
            <Popover open={selectorOpen} onOpenChange={handleSelectorOpenChange}>
                <PopoverTrigger asChild>
                    <Button
                        variant="outline"
                        className={cn("h-7", hasActiveFilters && "w-fit !px-2")}
                        onClick={() => setOpenPill(null)}
                    >
                        <FilterIcon className="size-4" />
                        {!hasActiveFilters && <span>Filtrer</span>}
                    </Button>
                </PopoverTrigger>
                <PopoverContent
                    className="w-fit p-0 origin-(--radix-popover-content-transform-origin)"
                    align="start"
                    side="bottom"
                >
                    {selectedColumn ? (
                        <div>
                            <button
                                type="button"
                                onClick={() => setSelectorColumn(null)}
                                className="flex items-center gap-1.5 px-3 py-2 text-sm text-muted-foreground hover:text-foreground w-full border-b"
                            >
                                {selectedColumn.icon && (
                                    <selectedColumn.icon className="size-4 stroke-[2.25px]" />
                                )}
                                <span>{selectedColumn.label}</span>
                            </button>
                            <FilterControl
                                column={selectedColumn}
                                value={activeFilters[selectedColumn.id]}
                                onSubmit={(op, vals) =>
                                    handleFilterSubmit(selectedColumn.id, op, vals)
                                }
                            />
                        </div>
                    ) : (
                        <Command
                            loop
                            filter={(value, searchTerm, keywords) => {
                                const ext = `${value} ${keywords?.join(" ")}`;
                                return ext.toLowerCase().includes(searchTerm.toLowerCase())
                                    ? 1
                                    : 0;
                            }}
                        >
                            <CommandInput
                                value={search}
                                onValueChange={setSearch}
                                ref={inputRef}
                                placeholder="Rechercher..."
                            />
                            <CommandEmpty>Aucun résultat.</CommandEmpty>
                            <CommandList className="max-h-fit">
                                {hasActiveFilters && (
                                    <>
                                        <CommandGroup>
                                            <CommandItem
                                                value="__clear_all__"
                                                onSelect={() => {
                                                    clearAllFilters();
                                                    setSelectorOpen(false);
                                                }}
                                                className="text-destructive"
                                            >
                                                <div className="flex items-center gap-1.5">
                                                    <Trash2 className="size-4" />
                                                    <span>Effacer tous les filtres</span>
                                                </div>
                                            </CommandItem>
                                        </CommandGroup>
                                        <Separator />
                                    </>
                                )}
                                <CommandGroup>
                                    {columns.map((col) => {
                                        const isActive = !!activeFilters[col.id];
                                        return (
                                            <CommandItem
                                                key={col.id}
                                                value={col.id}
                                                keywords={[col.label]}
                                                onSelect={() => {
                                                    setSearch("");
                                                    setSelectorColumn(col.id);
                                                }}
                                                className="group"
                                            >
                                                <div className="flex w-full items-center justify-between">
                                                    <div className="inline-flex items-center gap-1.5">
                                                        {col.icon && (
                                                            <col.icon
                                                                strokeWidth={2.25}
                                                                className="size-4"
                                                            />
                                                        )}
                                                        <span className={cn(isActive && "font-semibold")}>
                                                            {col.label}
                                                        </span>
                                                    </div>
                                                    <ArrowRightIcon
                                                        className="size-4 opacity-0 group-aria-selected:opacity-100" />
                                                </div>
                                            </CommandItem>
                                        );
                                    })}

                                    {/* Quick search: show option values matching search */}
                                    {search.trim().length >= 2 &&
                                        optionColumns.map((col) => {
                                            const current = activeFilters[col.id];
                                            const currentValues = new Set(current?.values ?? []);

                                            return (
                                                <React.Fragment key={`qs-${col.id}`}>
                                                    {col.options!.map((opt) => {
                                                        const checked = currentValues.has(opt.value);
                                                        return (
                                                            <CommandItem
                                                                key={`${col.id}-${opt.value}`}
                                                                value={opt.value}
                                                                keywords={[opt.label, opt.value, col.label]}
                                                                onSelect={() =>
                                                                    handleQuickOptionToggle(col.id, opt.value)
                                                                }
                                                                className="group"
                                                            >
                                                                <div className="flex items-center gap-1.5">
                                                                    <Checkbox
                                                                        checked={checked}
                                                                        className="opacity-0 data-[state=checked]:opacity-100 group-data-[selected=true]:opacity-100 dark:border-ring mr-1"
                                                                    />
                                                                    <div className="flex items-center gap-0.5">
                                                                        <span className="text-muted-foreground">
                                                                            {col.label}
                                                                        </span>
                                                                        <ChevronRightIcon
                                                                            className="size-3.5 text-muted-foreground/75" />
                                                                        <span>{opt.label}</span>
                                                                    </div>
                                                                </div>
                                                            </CommandItem>
                                                        );
                                                    })}
                                                </React.Fragment>
                                            );
                                        })}
                                </CommandGroup>
                            </CommandList>
                        </Command>
                    )}
                </PopoverContent>
            </Popover>

            {/* Active filter pills */}
            {Object.entries(activeFilters).map(([columnId, filterValue]) => {
                const col = columns.find((c) => c.id === columnId);
                if (!col) return null;

                const pillOpen = openPill?.columnId === columnId ? openPill.section : null;

                return (
                    <FilterPill
                        key={columnId}
                        column={col}
                        filterValue={filterValue}
                        openSection={pillOpen}
                        onSectionChange={(section) =>
                            handlePillSectionChange(columnId, section)
                        }
                        onClear={() => {
                            clearFilter(columnId);
                            closeAll();
                        }}
                        onSubmit={(op, vals) => handleFilterSubmit(columnId, op, vals)}
                    />
                );
            })}

        </div>
    );
}

import { Calendar } from "@/components/ui/calendar";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { isEqual } from "date-fns";
import { Search } from "lucide-react";
import { useMemo, useState } from "react";
import type { DateRange } from "react-day-picker";
import { DEFAULT_OPERATOR, OPERATORS, type FilterColumn, type FilterValue } from "./types";

interface FilterControlProps {
    column: FilterColumn;
    value?: FilterValue;
    onSubmit: (operator: string, values: string[]) => void;
    hideOperator?: boolean;
}

function OperatorSelect({
    type,
    value,
    onChange,
}: {
    type: FilterColumn["type"];
    value: string;
    onChange: (op: string) => void;
}) {
    const ops = OPERATORS[type];
    if (ops.length <= 1) return null;

    return (
        <Select value={value} onValueChange={onChange}>
            <SelectTrigger className="h-8 text-xs">
                <SelectValue />
            </SelectTrigger>
            <SelectContent>
                {ops.map((op) => (
                    <SelectItem key={op.value} value={op.value}>
                        {op.label}
                    </SelectItem>
                ))}
            </SelectContent>
        </Select>
    );
}

export function OptionFilter({ column, value, onSubmit, hideOperator }: FilterControlProps) {
    const [search, setSearch] = useState("");
    const [operator, setOperator] = useState(value?.operator || DEFAULT_OPERATOR.option);
    const selected = new Set(value?.values ?? []);

    const filteredOptions = useMemo(() => {
        if (!column.options) return [];
        if (!search) return column.options;
        const s = search.toLowerCase();
        return column.options.filter((o) => o.label.toLowerCase().includes(s));
    }, [column.options, search]);

    function toggle(optionValue: string) {
        const next = new Set(selected);
        if (next.has(optionValue)) next.delete(optionValue);
        else next.add(optionValue);
        onSubmit(operator, Array.from(next));
    }

    function handleOperatorChange(op: string) {
        setOperator(op);
        if (selected.size > 0) {
            onSubmit(op, Array.from(selected));
        }
    }

    const threshold = column.searchThreshold ?? 5;
    const showSearch = (column.options?.length ?? 0) >= threshold;

    return (
        <div className="flex flex-col gap-2 p-2 w-[260px]">
            {!hideOperator && <OperatorSelect type="option" value={operator} onChange={handleOperatorChange} />}
            {showSearch && (
                <div className="relative">
                    <Search className="absolute left-2 top-2 h-4 w-4 text-muted-foreground" />
                    <Input
                        placeholder="Rechercher..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="h-8 pl-8 text-sm"
                    />
                </div>
            )}
            <div className="max-h-[200px] overflow-y-auto flex flex-col gap-0.5">
                {filteredOptions.map((opt) => (
                    <label
                        key={opt.value}
                        className="flex items-center gap-2 rounded px-2 py-1.5 text-sm hover:bg-accent cursor-pointer"
                    >
                        <Checkbox
                            checked={selected.has(opt.value)}
                            onCheckedChange={() => toggle(opt.value)}
                        />
                        {opt.label}
                    </label>
                ))}
                {filteredOptions.length === 0 && (
                    <p className="text-sm text-muted-foreground px-2 py-1">Aucun résultat.</p>
                )}
            </div>
        </div>
    );
}

export function NumberFilter({ value, onSubmit, hideOperator }: FilterControlProps) {
    const [operator, setOperator] = useState(value?.operator || DEFAULT_OPERATOR.number);
    const [val1, setVal1] = useState(value?.values[0] ?? "");
    const [val2, setVal2] = useState(value?.values[1] ?? "");

    const isRange = OPERATORS.number.find((o) => o.value === operator)?.multi ?? false;

    function submit() {
        const values = isRange && val2 ? [val1, val2] : val1 ? [val1] : [];
        onSubmit(operator, values);
    }

    function handleOperatorChange(op: string) {
        setOperator(op);
        if (val1) {
            const multi = OPERATORS.number.find((o) => o.value === op)?.multi ?? false;
            const values = multi && val2 ? [val1, val2] : [val1];
            onSubmit(op, values);
        }
    }

    function handleKeyDown(e: React.KeyboardEvent) {
        if (e.key === "Enter") submit();
    }

    return (
        <div className="flex flex-col gap-2 p-2 w-[260px]">
            {!hideOperator && <OperatorSelect type="number" value={operator} onChange={handleOperatorChange} />}
            <div className={isRange ? "grid grid-cols-2 gap-2" : ""}>
                <Input
                    type="number"
                    placeholder={isRange ? "Min" : "Valeur"}
                    value={val1}
                    onChange={(e) => setVal1(e.target.value)}
                    onKeyDown={handleKeyDown}
                    autoFocus
                    className="h-8 text-sm"
                />
                {isRange && (
                    <Input
                        type="number"
                        placeholder="Max"
                        value={val2}
                        onChange={(e) => setVal2(e.target.value)}
                        onKeyDown={handleKeyDown}
                        className="h-8 text-sm"
                    />
                )}
            </div>
            <p className="text-xs text-muted-foreground">Appuyez sur Entrée pour filtrer</p>
        </div>
    );
}

export function DateFilter({ value, onSubmit, hideOperator }: FilterControlProps) {
    const [operator, setOperator] = useState(value?.operator || DEFAULT_OPERATOR.date);
    const isRange = OPERATORS.date.find((o) => o.value === operator)?.multi ?? false;

    const [date, setDate] = useState<DateRange | undefined>(() => {
        if (!value?.values.length) return undefined;
        return {
            from: new Date(value.values[0]),
            to: value.values[1] ? new Date(value.values[1]) : undefined,
        };
    });

    function fmt(d: Date): string {
        return d.toISOString().slice(0, 10);
    }

    function handleDateChange(range: DateRange | undefined) {
        setDate(range);
        if (!range?.from) return;

        if (isRange) {
            if (range.from && range.to && !isEqual(range.from, range.to)) {
                onSubmit(operator, [fmt(range.from), fmt(range.to)]);
            }
        } else {
            onSubmit(operator, [fmt(range.from)]);
        }
    }

    function handleOperatorChange(op: string) {
        setOperator(op);
        if (date?.from) {
            const multi = OPERATORS.date.find((o) => o.value === op)?.multi ?? false;
            if (multi && date.to) {
                onSubmit(op, [fmt(date.from), fmt(date.to)]);
            } else if (!multi) {
                onSubmit(op, [fmt(date.from)]);
            }
        }
    }

    return (
        <div className="flex flex-col gap-2 p-2">
            {!hideOperator && <OperatorSelect type="date" value={operator} onChange={handleOperatorChange} />}
            <Calendar
                mode="range"
                selected={date}
                onSelect={handleDateChange}
                numberOfMonths={1}
                initialFocus
            />
        </div>
    );
}

export function TextFilter({ value, onSubmit, hideOperator }: FilterControlProps) {
    const [operator, setOperator] = useState(value?.operator || DEFAULT_OPERATOR.text);
    const [text, setText] = useState(value?.values[0] ?? "");

    function submit() {
        if (text) onSubmit(operator, [text]);
        else onSubmit(operator, []);
    }

    function handleOperatorChange(op: string) {
        setOperator(op);
        if (text) onSubmit(op, [text]);
    }

    function handleKeyDown(e: React.KeyboardEvent) {
        if (e.key === "Enter") submit();
    }

    return (
        <div className="flex flex-col gap-2 p-2 w-[260px]">
            {!hideOperator && <OperatorSelect type="text" value={operator} onChange={handleOperatorChange} />}
            <Input
                placeholder="Rechercher..."
                value={text}
                onChange={(e) => setText(e.target.value)}
                onKeyDown={handleKeyDown}
                autoFocus
                className="h-8 text-sm"
            />
            <p className="text-xs text-muted-foreground">Appuyez sur Entrée pour filtrer</p>
        </div>
    );
}

const BOOL_OPTIONS = [
    { label: "Oui", value: "1" },
    { label: "Non", value: "0" },
];

export function FilterControl({ column, value, onSubmit, hideOperator }: FilterControlProps) {
    switch (column.type) {
        case "boolean":
            return (
                <OptionFilter
                    column={{ ...column, type: "option", options: BOOL_OPTIONS, searchThreshold: 999 }}
                    value={value}
                    onSubmit={onSubmit}
                    hideOperator
                />
            );
        case "option":
            return <OptionFilter column={column} value={value} onSubmit={onSubmit} hideOperator={hideOperator} />;
        case "number":
            return <NumberFilter column={column} value={value} onSubmit={onSubmit} hideOperator={hideOperator} />;
        case "date":
            return <DateFilter column={column} value={value} onSubmit={onSubmit} hideOperator={hideOperator} />;
        case "text":
            return <TextFilter column={column} value={value} onSubmit={onSubmit} hideOperator={hideOperator} />;
        default:
            return null;
    }
}

import type { LucideIcon } from "lucide-react";

export type FilterType = "text" | "number" | "date" | "option" | "boolean";

export interface FilterColumn {
